import React, { useEffect, useState } from 'react';
import axios from 'axios';

const GalleryPage = () => {
  const [images, setImages] = useState([]);

  useEffect(() => {
    const fetchGallery = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/gallery');
        setImages(res.data);
      } catch (error) {
        console.error('Failed to load gallery:', error);
      }
    };

    fetchGallery();
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 py-10 px-6 sm:px-12">
      <h2 className="text-4xl font-bold text-center mb-10 text-gray-800">
        📸 Proofing Gallery
      </h2>

      {images.length === 0 ? (
        <p className="text-center text-gray-500">No images to display.</p>
      ) : (
        <div className="grid gap-8 grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4">
          {images.map((img, index) => (
            <div
              key={index}
              className="bg-white rounded-2xl shadow-lg overflow-hidden hover:shadow-2xl transition duration-300 group"
            >
              <div className="overflow-hidden">
                <img
                  src={`http://localhost:5000${img.imageUrl}`}
                  alt={img.title}
                  className="w-full h-60 object-cover group-hover:scale-105 transition-transform duration-500"
                />
              </div>
              <div className="p-4 text-center">
                <h3 className="text-lg font-semibold text-gray-800">{img.title}</h3>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default GalleryPage;
